-function inferToolName(message?: ToolMessageLike): string | undefined {
-  if (!message) return undefined;
-  const candidates = [
-    message.toolName,
-    message.name,
-    message.toolCallId,
-    message.tool_call_id,
-  ]
-    .map((c) => (typeof c === "string" ? c.trim() : ""))
-    .filter(Boolean);
-  if (candidates.length) return candidates[0];
